import React from "react"
import { Location } from "@reach/router"
import { useIntl } from "gatsby-plugin-intl"
const { pathPrefix } = require("../../../gatsby-config")

const Tree = (Component: React.FC) => (props: UrlFragment[]) => {
  const { formatMessage } = useIntl()

  return <Location>
    {location => {
      let fragments = location.location.pathname
        .replace(pathPrefix, '')
        .split("/")
        .filter(f => f != "")
        .map(id => ({
          id,
          label: formatMessage({ id: `NAVIGATION__${id}`})
        }))

      return <Component fragments={fragments} {...props} />
    }
  }
  </Location>
}

interface UrlFragment {
  id: string
  url: string
}

export default Tree
export { UrlFragment }
